import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = defaultdict(int)

class GameServer:
    def __init__(self):
        self.players = {}
        self.connections = {}

    async def register(self, websocket):
        async for message in websocket:
            data = json.loads(message)
            if data['action'] == 'join':
                player = Player(data['username'])
                self.players[data['username']] = player
                self.connections[player.username] = websocket
                await self.send_inventory(player)

    async def send_inventory(self, player):
        inventory_data = {
            "action": "inventory_update",
            "inventory": dict(player.inventory)
        }
        await self.connections[player.username].send(json.dumps(inventory_data))

    async def trade_items(self, from_player, to_player, item, quantity):
        if from_player.inventory[item] >= quantity:
            from_player.inventory[item] -= quantity
            to_player.inventory[item] += quantity
            await self.send_inventory(from_player)
            await self.send_inventory(to_player)

    async def handle_trade(self, websocket, data):
        from_username = data['from']
        to_username = data['to']
        item = data['item']
        quantity = data['quantity']

        from_player = self.players.get(from_username)
        to_player = self.players.get(to_username)

        if from_player and to_player:
            await self.trade_items(from_player, to_player, item, quantity)

    async def handler(self, websocket, path):
        await self.register(websocket)

        async for message in websocket:
            data = json.loads(message)
            if data['action'] == 'trade':
                await self.handle_trade(websocket, data)

    def run(self, host='localhost', port=6789):
        server = websockets.serve(self.handler, host, port)
        asyncio.get_event_loop().run_until_complete(server)
        asyncio.get_event_loop().run_forever()

if __name__ == "__main__":
    game_server = GameServer()
    game_server.run()